   9 | import { recordAccessBatch } from './access-tracker.js'
  10 | import { logger } from "../logger.js";
  11 | 
  12 | let index: SearchIndex | null = null
  13 | let vectorIndex: VectorIndex | null = null
  14 | let currentEmbeddingProvider: EmbeddingProvider | null = null
  15 | 
  16 | export function getSearchIndex(): SearchIndex {
  17 |   if (!index) index = new SearchIndex()
  18 |   return index
  19 | }
  20 | 
