  41 | // Persistence sync hook. Without this, index removals only live in
  42 | // memory; a crash/SIGKILL before graceful shutdown reloads a stale
  43 | // snapshot at boot and the deleted entry resurrects in the index.
  44 | // Wired by src/index.ts after IndexPersistence is constructed; no-op
  45 | // until then so unit tests that exercise the delete paths in
  46 | // isolation don't need to wire persistence.
  47 | let indexPersistence: {
  48 |   scheduleSave: () => void;
  49 |   save: () => Promise<void>;
  50 | } | null = null;
  51 | 
  52 | export function setIndexPersistence(
  53 |   p: { scheduleSave: () => void; save: () => Promise<void> } | null,
  54 | ): void {
  55 |   indexPersistence = p;
  56 | }
  57 | 
  58 | export function scheduleIndexSave(): void {
  59 |   indexPersistence?.scheduleSave();
  60 | }
  61 | 
  62 | // Synchronous flush variant for delete paths. The debounced
  63 | // scheduleSave is fine for adds (chatty), but a hard process exit
  64 | // inside the 5s debounce window would lose deletes and resurrect
  65 | // removed entries on next boot. Deletes are infrequent enough that
  66 | // awaiting a single write per operation is acceptable. save() catches
  67 | // its own errors via IndexPersistence.logFailure, so this resolves
  68 | // even when persistence fails — callers must not treat a failed
  69 | // flush as a fatal error on the delete itself (the KV delete already
  70 | // committed before this is invoked).
  71 | export async function flushIndexSave(): Promise<void> {
  72 |   await indexPersistence?.save();
  73 | }
  74 | 
  75 | // Hard cap on embedding input length. Most providers cap input around
  76 | // 8k tokens (~32k chars at ~4 chars/token). Truncate defensively so a
  77 | // huge memory.content can't 400 the embed call or blow context budget
  78 | // on a single doc. 16k chars ≈ 4k tokens, safely under every provider.
  79 | const EMBED_MAX_CHARS = 16_000
  80 | 
  81 | export function clipEmbedInput(text: string): string {
  82 |   if (text.length <= EMBED_MAX_CHARS) return text
  83 |   return text.slice(0, EMBED_MAX_CHARS)
  84 | }
